#include <stdio.h>
#include <stdlib.h>

void findCombination(int ind, int target, int* arr, int** ans, int* ansSize, int** ds, int* dsSize) {
    if (target == 0) {
        ans[*ansSize] = (int*)malloc((*dsSize) * sizeof(int));
        for (int i = 0; i < *dsSize; i++) {
            ans[*ansSize][i] = ds[0][i];
        }
        (*ansSize)++;
        return;
    }

    for (int i = ind; i < 100; i++) {
        if (i > ind && arr[i] == arr[i - 1]) continue;
        if (arr[i] > target) break;
        ds[0][*dsSize] = arr[i];
        (*dsSize)++;
        findCombination(i + 1, target - arr[i], arr, ans, ansSize, ds, dsSize);
        (*dsSize)--;
    }
}

int** combinationSum2(int* candidates, int candidatesSize, int target, int* returnSize) {
