            ds.push(arr[i]);

            // Recur with the updated target and next index (i + 1 to avoid repetition)
            this.findCombination(i + 1, target - arr[i], arr, ans, ds);

            // Backtrack by removing the last added element
            ds.pop();
        }
    }

